import com.maum.backend.entity.call.CallStatus
import com.maum.backend.repository.call.CallRepository
import org.assertj.core.api.Assertions.assertThat
import org.junit.jupiter.api.DisplayName
import org.junit.jupiter.api.Nested
import org.junit.jupiter.api.Test
import org.junit.jupiter.api.assertThrows
import org.junit.jupiter.api.extension.ExtendWith
import org.mockito.InjectMocks
import org.mockito.Mock
import org.mockito.junit.jupiter.MockitoExtension
import org.mockito.kotlin.any
import org.mockito.kotlin.argumentCaptor
import org.mockito.kotlin.verify
import org.mockito.kotlin.whenever
import java.time.LocalDateTime
import java.util.Optional

@ExtendWith(MockitoExtension::class)
@DisplayName("CallService 테스트")
class CallServiceTest {

    @Mock
    private lateinit var callRepository: CallRepository

    @InjectMocks
    private lateinit var callService: CallService

    // -------------------------------------------------------------------------
    // initiateCall
    // -------------------------------------------------------------------------
    @Nested
    @DisplayName("initiateCall - 통화 생성")
    inner class InitiateCallTest {

        @Test
        fun `should create call when caller and receiver are different users`() {
            // given
            val callerId = "user-A"
            val receiverId = "user-B"
            val savedCall = CallEntity(
                id = "call-1",
                callerId = callerId,
                receiverId = receiverId,
                status = CallStatus.WAITING,
            )
            whenever(callRepository.save(any())).thenReturn(savedCall)

            // when
            val result = callService.initiateCall(callerId, receiverId)

            // then
            assertThat(result.callerId).isEqualTo(callerId)
            assertThat(result.receiverId).isEqualTo(receiverId)
            assertThat(result.status).isEqualTo(CallStatus.WAITING)
            verify(callRepository).save(any())
        }

        /**
         * [TDD Red] 버그 #1: 자기 자신에게 통화 시 예외가 발생해야 하지만, 현재는 통화가 생성됨
         */
        @Test
        fun `should throw when caller and receiver are the same user`() {
            // given
            val userId = "user-A"

            // when & then
            assertThrows<IllegalArgumentException> {
                callService.initiateCall(callerId = userId, receiverId = userId)
            }
        }

        @Test
        fun `should throw when callerId is blank`() {
            // given & when & then
            assertThrows<IllegalArgumentException> {
                callService.initiateCall(callerId = "", receiverId = "user-B")
            }
        }

        @Test
        fun `should throw when receiverId is blank`() {
            // given & when & then
            assertThrows<IllegalArgumentException> {
                callService.initiateCall(callerId = "user-A", receiverId = "")
            }
        }
    }

    // -------------------------------------------------------------------------
    // acceptCall
    // -------------------------------------------------------------------------
    @Nested
    @DisplayName("acceptCall - 통화 수락")
    inner class AcceptCallTest {

        @Test
        fun `should accept call and set startedAt when call is in WAITING status`() {
            // given
            val callId = "call-1"
            val waitingCall = CallEntity(
                id = callId,
                callerId = "user-A",
                receiverId = "user-B",
                status = CallStatus.WAITING,
            )
            whenever(callRepository.findById(callId)).thenReturn(Optional.of(waitingCall))
            whenever(callRepository.save(any())).thenAnswer { it.arguments[0] }

            // when
            val result = callService.acceptCall(callId)

            // then
            assertThat(result.status).isEqualTo(CallStatus.ONGOING)
            assertThat(result.startedAt).isNotNull
        }

        /**
         * [TDD Red] 버그 #2: 이미 ONGOING 상태인 통화를 다시 수락해도 예외가 발생하지 않음
         */
        @Test
        fun `should throw when trying to accept a call that is already ONGOING`() {
            // given
            val callId = "call-1"
            val ongoingCall = CallEntity(
                id = callId,
                callerId = "user-A",
                receiverId = "user-B",
                status = CallStatus.ONGOING,
                startedAt = LocalDateTime.now().minusMinutes(5),
            )
            whenever(callRepository.findById(callId)).thenReturn(Optional.of(ongoingCall))

            // when & then
            assertThrows<IllegalStateException> {
                callService.acceptCall(callId)
            }
        }

        /**
         * [TDD Red] 버그 #2 (변형): 이미 ENDED 상태인 통화를 수락해도 예외가 발생하지 않음
