        fun `should throw when trying to accept a call that is already ENDED`() {
            // given
            val callId = "call-1"
            val endedCall = CallEntity(
                id = callId,
                callerId = "user-A",
                receiverId = "user-B",
                status = CallStatus.ENDED,
                startedAt = LocalDateTime.now().minusMinutes(10),
                endedAt = LocalDateTime.now().minusMinutes(1),
            )
            whenever(callRepository.findById(callId)).thenReturn(Optional.of(endedCall))

            // when & then
            assertThrows<IllegalStateException> {
                callService.acceptCall(callId)
            }
        }

