```kotlin
package com.maum.backend.service

import com.maum.backend.entity.call.CallEntity
import com.maum.backend.entity.call.CallStatus
import com.maum.backend.repository.call.CallRepository
import org.springframework.stereotype.Service
import java.time.LocalDateTime
import java.time.Duration

@Service
class CallService(
    private val callRepository: CallRepository,
) {
    /**
     * 통화 생성 (발신)
     * 버그: callerId == receiverId 검증 누락
     */
    fun initiateCall(callerId: String, receiverId: String): CallEntity {
        // 버그: 자기 자신에게 통화 가능 - 아래 검증이 없음
        // if (callerId == receiverId) throw IllegalArgumentException("자기 자신에게 통화할 수 없습니다.")
        val call = CallEntity(
            callerId = callerId,
            receiverId = receiverId,
            status = CallStatus.WAITING,
        )
        return callRepository.save(call)
    }

    /**
     * 수신 수락
     * 버그: WAITING 상태 검증 누락 → 이미 ONGOING/ENDED인 통화도 재수락 가능
     */
    fun acceptCall(callId: String): CallEntity {
        val call = callRepository.findById(callId)
            .orElseThrow { NoSuchElementException("통화를 찾을 수 없습니다: $callId") }

        // 버그: 상태 검증 없이 ONGOING으로 전환
        // if (call.status != CallStatus.WAITING) throw IllegalStateException("WAITING 상태의 통화만 수락할 수 있습니다.")
        call.status = CallStatus.ONGOING
        call.startedAt = LocalDateTime.now()
        call.updatedAt = LocalDateTime.now()
        return callRepository.save(call)
    }

    /**
     * 통화 종료
     * 버그: endedAt 미설정
     */
    fun endCall(callId: String): CallEntity {
        val call = callRepository.findById(callId)
            .orElseThrow { NoSuchElementException("통화를 찾을 수 없습니다: $callId") }

        call.status = CallStatus.ENDED
        // 버그: endedAt 설정 누락
        // call.endedAt = LocalDateTime.now()
        call.updatedAt = LocalDateTime.now()
        return callRepository.save(call)
    }

    /**
     * 통화 시간(초) 계산
     * 버그: startedAt이 null일 때 NPE
     */
    fun calculateDurationSeconds(callId: String): Long {
        val call = callRepository.findById(callId)
            .orElseThrow { NoSuchElementException("통화를 찾을 수 없습니다: $callId") }

        // 버그: null 체크 없이 접근 → NPE
        val ended = call.endedAt ?: LocalDateTime.now()
        return Duration.between(call.startedAt, ended).seconds // startedAt null이면 NPE
    }

    /**
     * 부재중 처리
     * 버그: WAITING 상태 검증 누락
     */
    fun markAsMissed(callId: String): CallEntity {
        val call = callRepository.findById(callId)
            .orElseThrow { NoSuchElementException("통화를 찾을 수 없습니다: $callId") }

        // 버그: WAITING이 아닌 통화도 MISSED로 변경 가능
        // if (call.status != CallStatus.WAITING) throw IllegalStateException("WAITING 상태의 통화만 부재중 처리할 수 있습니다.")
        call.status = CallStatus.MISSED
        call.updatedAt = LocalDateTime.now()
        return callRepository.save(call)
    }
}
